109→
110→    const handleClickNotif = handleCLickContent(navigate);
111→    const handleClickOpinionNotif = handleClickOpinion(navigate);
112→    const mutationReadNotif = useReadNotificationMutation(session);
113→
114→    const handleReadNotif = async(e, notification) => {
115→        e.stopPropagation();
116→        const source = notification?.source || 'journal';
117→        mutationReadNotif.mutate({notifId: notification.id, source})
118→
119→        if(source === 'opinion'){
120→            handleClickOpinionNotif(e, notification?.opinions?.id, notification?.opinions?.user_id)
121→        } else if(notification?.type === 'follow'){
122→            navigate(`/visitProfile?userId=${notification?.sender_id}`);
123→        } else if(notification?.type === 'repost' && notification?.repost_journal_id){
124→            // Navigate to the repost post (quote + embedded original)
125→            const repostId = notification.repost_journal_id;
126→            const encodedId = encodeURIComponent(repostId);
127→            navigate(`/home/post/${encodedId}`);
128→        } else {
129→            const parsedContent = ParseContent(notification?.journals?.content);
130→            handleClickNotif(
131→                e,
132→                notification?.journals?.content,
133→                parsedContent.wholeText,
134→                notification?.journals?.title,
135→                notification?.journals?.users.id,
136→                notification?.journals?.users?.name,
137→                notification?.journals?.users?.image_url,
138→                notification?.journals?.created_at,
139→                notification?.journal_id,
140→                notification?.hasLiked,
141→                notification?.journals?.comments[0].count,
142→                notification?.hasBookMarked,
143→                notification?.journals?.likes[0].count,
144→                notification?.journals?.bookmarks[0].count,
145→                notification?.journals?.users?.badge,
146→            )
147→        }
148→    }
149→
150→    const {data, isLoading, hasNextPage, isFetchingNextPage, fetchNextPage} = useInfiniteQuery({
151→        queryKey: ['getNotifications', session?.user?.id],
152→        queryFn: ({pageParam = null}) => getNotifications(session?.access_token, pageParam, 5),
153→        getNextPageParam: (lastpage) =>{
154→            if(lastpage?.hasMore){
155→                const lastNotification = lastpage?.data[lastpage?.data.length - 1];
156→                return new Date(lastNotification.created_at).toISOString();
157→
158→            }
159→            return undefined;
160→        },
161→        enabled: !!session?.access_token,
162→        refetchOnWindowFocus: false,
163→        staleTime: 1000 * 60 * 2
164→    })
165→
166→    useEffect(() =>{
167→        if(scrollToTop.current && !isLoading){
168→            scrollToTop.current.scrollIntoView({behavior: 'smooth'});
169→        }
170→    }, [isLoading])
171→
172→    useEffect(() =>{
173→        if(hasNextPage && !isFetchingNextPage && inView){
174→            // console.log(hasNextPage)
175→            fetchNextPage();
176→        }
177→    }, [hasNextPage, isFetchingNextPage, inView, fetchNextPage])
178→
179→    const notifications = data?.pages?.flatMap((page) => page?.data) || [];
180→
181→    useEffect(() =>{
182→        const handleClickOutside = (e) =>{
183→            if(modalRef.current && !modalRef.current.contains(e.target)){
184→                setSettingsId(null);
185→                // console.log('close')
186→            }
187→        }
188→
189→        document.addEventListener('click', handleClickOutside);
190→        return () =>{
191→            document.removeEventListener('click', handleClickOutside)
192→        }
193→    }, [])
194→
195→     useEffect(() =>{
196→         // console.log(data)
197→    }, [data])
198→
199→    const handleClickSettings = (e, notifId) =>{
200→        e.stopPropagation();
201→        // console.log(notifId)
202→        setSettingsId(settingsId === notifId ? null : notifId);
203→    }
204→
205→    const mutationDeleteNotif  = useUserDeleteNotificationMutation(session);
206→
207→    const handleClickDeleteNotification = async(e, notifId, source) =>{
208→        e.stopPropagation();
209→        try {
210→           const message = mutationDeleteNotif.mutateAsync({notifId, source});
211→            if(message){
212→                // console.log(message)
213→            }
214→        } catch (error) {
215→            console.error('error while deleting notification:', error)
216→        }
217→    }
218→
219→    if(notifications.length === 0 && !isLoading){
220→        return(
221→            <div className='notification-loading-container'>
222→                No notifications availabe
223→            </div>
224→        )
225→    }
226→
227→    if(isLoading){
228→        return(
229→            <div className="notification-loading-container">
230→                <MoonLoader size={25} color="var(--loader-color)" loading={isLoading}/>
231→            </div>
232→        )
233→    }
234→
235→    return(
236→        <>
237→        <div ref={scrollToTop}/>
238→        <div className="notifications-container">
239→            {notifications?.map((notification) => {
240→                const isOpinion = notification?.source === 'opinion';
241→                const displayType = isOpinion ? 'opinion_reply' : notification?.type;
242→                const parsedContent = !isOpinion ? ParseContent(notification?.journals?.content) : null;
243→
244→                return(
245→                <div key={`${notification.source}-${notification.id}`} className={notification?.read ? "notification-cards" : "notification-cards-unread"}>
246→
247→                    <div className="notification-cards-child-container">
248→
249→                        <div className="notification-icon-container">
250→                            {displayType === 'reaction' ? (
251→                                <div className="notification-icon">
252→                                    <span style={{ fontSize: '26px', lineHeight: 1 }}>{getReactionEmoji(notification?.reaction_type) || '❤️'}</span>
253→                                </div>
254→                            ) : (
255→                                iconArray.map((icon, index) => (
256→                                    <div className="notification-icon" key={index}>
257→                                        {icon.type === displayType ? icon.icon : null}
258→                                    </div>
259→                                ))
260→                            )}
261→                        </div>
262→
263→                        <div className="notification-contents-container">
264→
265→                            <div className="notification-sender-user-metadata">
266→                                <div className="notification-sender-user-metadata-child">
267→                                    <div className={`notif-sender-profilepic-container ${notification?.users?.badge === 'legend' ? 'notif-avatar-ring-legend' : notification?.users?.badge === 'og' ? 'notif-avatar-ring-og' : ''}`}>
268→                                        <img loading="lazy" className="notif-sender-profilepic" src={notification?.users?.image_url || '/assets/profile.jpg'} alt="notificataion sender profile picture" />
269→                                    </div>
270→
271→                                    <div className="notif-sender-name-container">
272→                                        <p className="notif-sender-name">{notification?.users?.name}</p>
273→                                        <VerifiedBadge badge={notification?.users?.badge} size={14} />
274→                                        <p className="notif-type">{FormatNotificationType(displayType, notification?.reaction_type)}</p>
275→                                    </div>
276→
277→                                    <div className="notification-date-container">
278→                                        <p className="notification-date">{formatPostDate(notification?.created_at)}</p>
279→                                    </div>
280→                                </div>
281→                                <div className="notification-settings">
282→                                    {settingsId === notification.id && (
283→                                        <AnimatePresence>
284→                                        <motion.div
285→                                        initial={{opacity: 0, scale: 0}}
286→                                        animate={{opacity: 1, scale: 1, transition:{type: 'spring', stiffness: 300, damping: 25, mass: 0.8}}}
287→                                        exit={{ opacity: 0, scale: 0,
288→                                            transition: {
289→                                            duration: 0.2,
290→                                            ease: "easeOut"
291→                                            }
292→                                        }}
293→                                        ref={modalRef}
294→                                        className="settings-container">
295→
296→                                            <div onClick={(e) => handleClickDeleteNotification(e, notification?.id, notification?.source)} className="delete-notification">
297→                                                <svg xmlns="http://www.w3.org/2000/svg" width="20px" height="20px" viewBox="0 0 24 24" fill="none">
298→                                                    <path d="M10 12V17" stroke="#000000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
299→                                                    <path d="M14 12V17" stroke="#000000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
300→                                                    <path d="M4 7H20" stroke="#000000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
301→                                                    <path d="M6 10V18C6 19.6569 7.34315 21 9 21H15C16.6569 21 18 19.6569 18 18V10" stroke="#000000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
302→                                                    <path d="M9 5C9 3.89543 9.89543 3 11 3H13C14.1046 3 15 3.89543 15 5V7H9V5Z" stroke="#000000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
303→                                                </svg>
304→                                                Delete this notification
305→                                            </div>
306→
307→                                        </motion.div>
308→                                        </AnimatePresence>
309→                                    )}
310→
311→                                    <svg onClick={(e) => handleClickSettings(e, notification?.id)} xmlns="http://www.w3.org/2000/svg" width="20px" height="20px" viewBox="0 0 24 24" fill="none">
312→                                        <g id="style=fill">
313→                                            <g id="menu-meatballs">
314→                                                <path id="vector (Stroke)" fillRule="evenodd" clipRule="evenodd" d="M2.75 12C2.75 10.7574 3.75736 9.75 5 9.75C6.24264 9.75 7.25 10.7574 7.25 12C7.25 13.2426 6.24264 14.25 5 14.25C3.75736 14.25 2.75 13.2426 2.75 12Z" fill="#000000"/>
315→                                                <path id="vector (Stroke)_2" fillRule="evenodd" clipRule="evenodd" d="M9.75 12C9.75 10.7574 10.7574 9.75 12 9.75C13.2426 9.75 14.25 10.7574 14.25 12C14.25 13.2426 13.2426 14.25 12 14.25C10.7574 14.25 9.75 13.2426 9.75 12Z" fill="#000000"/>
316→                                                <path id="vector (Stroke)_3" fillRule="evenodd" clipRule="evenodd" d="M16.75 12C16.75 10.7574 17.7574 9.75 19 9.75C20.2426 9.75 21.25 10.7574 21.25 12C21.25 13.2426 20.2426 14.25 19 14.25C17.7574 14.25 16.75 13.2426 16.75 12Z" fill="#000000"/>
317→                                            </g>
318→                                        </g>
319→                                    </svg>
320→                                </div>
321→
322→                            </div>
323→
324→                            <div
325→                            className="notification-content"
326→                            onClick={(e) => handleReadNotif(e, notification)}
327→                            >
328→                                {displayType === 'follow' ? (
329→                                    <div className="notification-content-text">
330→                                        <p className="notif-content-sliced-text">started following you</p>
331→                                    </div>
332→                                ) : isOpinion ? (
333→                                    <div className="notification-content-text">
334→                                        <p className="notif-content-sliced-text">{notification?.opinions?.opinion?.length > 100 ? notification?.opinions?.opinion?.substring(0, 100) + '...' : notification?.opinions?.opinion}</p>
335→                                    </div>
336→                                ) : (
337→                                    <>
338→                                    <div className="notification-content-text">
339→                                        <p className="notif-content-title">{notification?.journals?.title?.length > 40 ? notification?.journals?.title?.substring(0, 39) : notification?.journals?.title}</p>
340→                                        <p className="notif-content-sliced-text">{parsedContent?.slicedText}</p>
341→                                    </div>
342→                                    <div className="notif-content-image-container">
343→                                        <img loading="lazy" className="notif-content-image" src={parsedContent?.firstImage?.src || '/assets/no-image.png'} alt={notification?.journals?.title ? `${notification.journals.title} cover image` : "Notification post cover image"} onError={handleImageFallback} />
344→                                    </div>
345→                                    </>
346→                                )}
347→                            </div>
